// Compile the Morning Brief as FOUR clean, formal messages (repo mounted read-only at /data/swingby):
//   1/4 Backend · 2/4 Mobile/Frontend · 3/4 Requires Your Action · 4/4 Overnight Summary
// Output is sanitised: all Markdown/Obsidian noise (**bold**, `code`, ###, [[links]], - [ ],
// middot separators) is stripped, text is clipped on word/sentence boundaries, and section
// headers use Telegram HTML (parse_mode=HTML on the send node). Each item carries tokenVar so
// each section can post from its own bot (TELEGRAM_BOT_TOKEN_* in n8n.env; falls back to TELEGRAM_BOT_TOKEN).
const fs = require('fs');
const read = (p) => { try { return fs.readFileSync(p, 'utf8'); } catch (e) { return ''; } };
const MEM = '/data/swingby/AGENTS/claude/memory/';

const status = read(MEM + 'STATUS.md');
const todo   = read(MEM + 'HUMAN-TODO.md');
const slog   = read(MEM + 'SESSION_LOG.md');
const onlog  = read('/data/swingby/AGENTS/claude/automation/overnight.log');

// --- text hygiene ------------------------------------------------------------
// Strip Markdown / Obsidian formatting down to plain prose.
const clean = (s) => (s || '')
  .replace(/`{1,3}([^`]*)`{1,3}/g, '$1')            // `code`
  .replace(/`/g, '')                                 // stray backticks
  .replace(/\*\*([^*]+)\*\*/g, '$1')                 // **bold**
  .replace(/\*([^*]+)\*/g, '$1')                     // *italic*
  .replace(/~~([^~]+)~~/g, '$1')                     // ~~strike~~
  .replace(/\[\[[^\]|]*\|([^\]]+)\]\]/g, '$1')       // [[target|label]] -> label
  .replace(/\[\[([^\]]+)\]\]/g, '$1')                // [[wikilink]] -> text
  .replace(/\[([^\]]+)\]\([^)]*\)/g, '$1')           // [label](url) -> label
  .replace(/^#{1,6}\s*/, '')                         // leading heading hashes
  .replace(/^\s*[-*]\s*\[[ xX]\]\s*/, '')            // checkbox marker
  .replace(/^\s*[-*•]\s+/, '')                       // leading list bullet
  .replace(/^\s*\d+\.\s+/, '')                       // leading "1. "
  .replace(/^\(([^)]{2,90})\)[\s:—–-]*/, '')          // leading "(tag)" label
  .replace(/\s*·\s*/g, ' — ')                        // middot separator -> em dash
  .replace(/[ \t]+/g, ' ')
  .trim();

// Escape for Telegram parse_mode=HTML. Apply ONLY to dynamic text, never to our own tags.
const esc = (s) => (s || '')
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

// Clip to n chars on a sentence, then word, boundary — never mid-word.
const clip = (s, n) => {
  s = (s || '').trim();
  if (s.length <= n) return s;
  const cut = s.slice(0, n);
  const stop = Math.max(cut.lastIndexOf('. '), cut.lastIndexOf('; '));
  if (stop > n * 0.55) return cut.slice(0, stop + 1).trim();
  return cut.replace(/\s+\S*$/, '').trim() + '…';
};

// One clean, escaped bullet.
const bullet = (text, max) => '• ' + esc(clip(clean(text), max || 260));

// Body of a '## Heading' section ('###' subheadings stay inside).
const section = (src, heading, hashes) => {
  hashes = hashes || '##';
  const h = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = new RegExp('^' + hashes + ' .*' + h + '.*$', 'm').exec(src);
  if (!m) return '';
  const rest = src.slice(m.index + m[0].length);
  const next = rest.search(new RegExp('^' + hashes + ' ', 'm'));
  return (next === -1 ? rest : rest.slice(0, next)).trim();
};

// Turn a section body into clean bullets (skips sub-headings and blank lines).
const toBullets = (body, max, cap) => {
  const out = [];
  for (let l of (body || '').split('\n')) {
    l = l.trim();
    if (!l || /^#{1,6}\s/.test(l)) continue;
    const c = clean(l);
    if (c.length < 3) continue;
    out.push(bullet(c, cap || 260));
    if (out.length >= (max || 12)) break;
  }
  return out;
};

// Unchecked "- [ ]" items from a section, each carrying its indented sub-steps
// (so multi-line tasks never end mid-sentence). Done items are skipped entirely.
const taskItems = (body, max) => {
  const items = [];
  let cur = null;
  for (const raw of (body || '').split('\n')) {
    if (/^\s*[-*]\s*\[ \]/.test(raw)) {
      if (items.length >= (max || 8)) break;
      cur = { head: raw.trim(), subs: [] };
      items.push(cur);
    } else if (/^\s*[-*]\s*\[[xX]\]/.test(raw) || /^#{1,6}\s/.test(raw)) {
      cur = null;
    } else if (cur && /^\s+\S/.test(raw)) {
      cur.subs.push(raw.trim());
    } else if (!raw.trim()) {
      cur = null;
    }
  }
  return items;
};

// Decisions get pulled to the top of the human message — Kira decides, never digs.
const isDecision = (t) => /decision|your call|decide/i.test(t.head);

// Render one task: headline bullet + up to 3 short numbered sub-steps.
const renderTask = (t) => {
  const out = ['• ' + esc(clip(clean(t.head), 240))];
  t.subs.slice(0, 3).forEach((s, i) => {
    out.push('    ' + (i + 1) + '. ' + esc(clip(clean(s), 110)));
  });
  if (t.subs.length > 3) out.push('    …full steps in HUMAN-TODO.md');
  return out.join('\n');
};
const renderTasks = (arr) => arr.map(renderTask).join('\n');

// Night-recap bullets reduced to headlines (text before ':' — detail stays in STATUS.md).
const headlines = (body, max) => (body || '')
  .split('\n')
  .filter((l) => /^\s*[•\-]\s/.test(l))
  .map((l) => clean(l).split(':')[0].split(' — ')[0].trim())
  .filter((l) => l.length > 2)
  .slice(0, max || 8)
  .map((l) => '• ' + esc(clip(l, 90)));

// Overnight log tail, stripped of timestamps and divider/symbol-only lines.
const logSummary = (raw, max) => {
  if (!raw) return ['• Overnight loop did not run.'];
  const lines = raw.trim().split('\n')
    .map((l) => l.trim())
    .filter(Boolean)
    .filter((l) => !/^\[[A-Za-z]{3}\s/.test(l))       // drop "[Thu Jul 16 ...]" stamps
    .filter((l) => !/^[-=_*#>·•\s]+$/.test(l))         // drop rule/symbol-only lines
    .filter((l) => !/^(Traceback|File "|at |\s+File )/.test(l)) // never raw stack traces
    .map((l) => clean(l))
    .filter((l) => l.length > 8);
  const tail = lines.slice(-(max || 4)).map((l) => '• ' + esc(clip(l, 220)));
  return tail.length ? tail : ['• No readable log output.'];
};

// --- gather ------------------------------------------------------------------
const signal = section(status, 'Session End Signal');
const signalHead = clean((signal.split('\n')[0] || '').trim()) || 'No signal recorded — see STATUS.md';

// Preferred: an explicit '## Morning Brief' with '### Backend'/'### Frontend'/'### Recap'.
// Fallback: bucket the Session End Signal bullets by keyword (both/neither -> recap).
const mb = section(status, 'Morning Brief');
let backend = section(mb, 'Backend', '###');
let frontend = section(mb, 'Frontend', '###');
let recapBody = section(mb, 'Recap', '###');

if (!backend && !frontend) {
  const sLines = signal.split('\n');
  const bullets = sLines.filter((l) => /^\s*[-•]\s/.test(l));
  const prose = sLines.slice(1).filter((l) => l.trim() && !/^\s*[-•]\s/.test(l)).join('\n');
  const isBack = (b) => /backend|fastapi|pytest|endpoint|\.py\b|supabase|migration|\bsql\b|render|stripe|conftest/i.test(b);
  const isFront = (b) => /mobile|frontend|screen|expo|babel|react|\bRN\b|gesture|navigation|App\.js|\.js\b|safearea/i.test(b);
  const back = [], front = [], rest = [];
  for (const b of bullets) {
    const bb = isBack(b), ff = isFront(b);
    if (bb && !ff) back.push(b);
    else if (ff && !bb) front.push(b);
    else rest.push(b);
  }
  backend = back.join('\n');
  frontend = front.join('\n');
  recapBody = [rest.join('\n'), prose].filter(Boolean).join('\n\n');
}

const todoAll     = taskItems(section(todo, 'This morning'), 8);
const decisions   = todoAll.filter(isDecision);
const doItems     = todoAll.filter((t) => !isDecision(t));
const blockItems  = taskItems(section(todo, 'Blocking'), 6);
const nextActions = toBullets(section(status, 'Next Action'), 6);

const loopNext = clean((slog.match(/^NEXT:.*$/gm) || []).pop() || '');
const today = new Date().toLocaleDateString('en-CA', {
  timeZone: 'America/Edmonton', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Join parts (keeping '' as blank-line spacers, dropping null), collapse runs of blank
// lines, then cap at a newline boundary (never splits a tag).
const build = (parts) => {
  const s = parts.filter((p) => p != null).join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/^\n+|\n+$/g, '')
    .trim();
  if (s.length <= 3900) return s;
  const at = s.lastIndexOf('\n', 3900);
  return s.slice(0, at > 0 ? at : 3900).trim();
};

const backBullets  = toBullets(backend, 12);
const frontBullets = toBullets(frontend, 12);
const recapBullets = headlines(recapBody, 8);

const messages = [
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_BACKEND',
    text: build([
      '☀️ <b>SwingBy — Morning Briefing</b>',
      esc(today) + ' · Part 1 of 4',
      '',
      '<b>Overall status</b>',
      esc(clip(signalHead, 320)),
      '',
      '<b>🔧 Backend</b>',
      backBullets.length ? backBullets.join('\n') : '• No backend changes overnight.'
    ])
  },
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_FRONTEND',
    text: build([
      '📱 <b>Mobile / Frontend</b>',
      'Part 2 of 4',
      '',
      frontBullets.length ? frontBullets.join('\n') : '• No mobile changes overnight.'
    ])
  },
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_HUMAN',
    text: build([
      '✅ <b>Requires Your Action</b>',
      'Part 3 of 4',
      '',
      decisions.length ? '<b>Decide today — one line back is enough</b>' : null,
      decisions.length ? renderTasks(decisions) : null,
      decisions.length ? '' : null,
      '<b>Do this morning</b>',
      doItems.length ? renderTasks(doItems) : '• Nothing queued — enjoy the coffee.',
      '',
      '<b>Blocked until you act</b>',
      blockItems.length ? renderTasks(blockItems) : '• Nothing is blocked.',
      '',
      '<b>Next actions</b>',
      nextActions.length ? nextActions.join('\n') : '• None recorded.'
    ])
  },
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_NIGHT',
    text: build([
      '🌙 <b>Overnight Summary</b>',
      'Part 4 of 4',
      '',
      recapBullets.length ? recapBullets.join('\n') : '• A quiet night — no notable activity.',
      '',
      '<b>Build log</b>',
      logSummary(onlog, 4).join('\n'),
      loopNext ? '' : null,
      loopNext ? '<b>Next in loop:</b> ' + esc(clip(loopNext.replace(/^NEXT:\s*/, ''), 200)) : null
    ])
  }
];

return messages.map((m) => ({ json: m }));
